// Rakip fiyat verilerini birleştir
const ourProducts = $input.items.find(i => i.json.source === 'products')?.json;
const trendyol = $input.items.find(i => i.json.source === 'trendyol')?.json || [];
const hepsiburada = $input.items.find(i => i.json.source === 'hepsiburada')?.json || [];
const amazon = $input.items.find(i => i.json.source === 'amazon')?.json || [];

const aggregated = ourProducts.map(product => {
  const sku = product.sku;

  const tPrice = trendyol.find(t => t.sku === sku)?.price;
  const hPrice = hepsiburada.find(h => h.sku === sku)?.price;
  const aPrice = amazon.find(a => a.sku === sku)?.price;

  const competitorPrices = [tPrice, hPrice, aPrice].filter(p => p != null);
  const minCompetitorPrice = Math.min(...competitorPrices);
  const avgCompetitorPrice = competitorPrices.reduce((a, b) => a + b, 0) / competitorPrices.length;

  return {
    json: {
      productId: product.id,
      sku: product.sku,
      productName: product.name,
      ourPrice: product.current_price,
      costPrice: product.cost_price,
      minCompetitorPrice,
      avgCompetitorPrice,
      competitorCount: competitorPrices.length,
      priceGap: product.current_price - minCompetitorPrice,
      priceGapPercent: ((product.current_price - minCompetitorPrice) / minCompetitorPrice) * 100,
      lastUpdated: new Date().toISOString()
    }
  };
});

return aggregated;

